+#[test]
+fn hints_all_variants_produce_nonempty_summary() {
+    let errors: Vec<Error> = vec![
+        Error::config("test"),
+        Error::session("test"),
+        Error::SessionNotFound {
+            path: "/test".to_string(),
+        },
+        Error::provider("p", "test"),
+        Error::auth("test"),
+        Error::tool("t", "test"),
+        Error::validation("test"),
+        Error::extension("test"),
+        io::Error::new(ErrorKind::Other, "test").into(),
+        serde_json::from_str::<serde_json::Value>("bad").unwrap_err().into(),
+        Error::Aborted,
+        Error::api("test"),
+    ];
+
+    for err in &errors {
+        let h = err.hints();
+        assert!(
+            !h.summary.is_empty(),
+            "hints().summary is empty for error: {err}"
+        );
+    }
+}
+
+#[test]
+fn hints_context_always_has_details_or_path() {
+    // Every variant except Aborted should include context with details or path
+    let errors: Vec<Error> = vec![
+        Error::config("test"),
+        Error::session("test"),
+        Error::SessionNotFound {
+            path: "/test".to_string(),
+        },
+        Error::provider("p", "test"),
+        Error::auth("test"),
+        Error::tool("t", "test"),
+        Error::validation("test"),
+        Error::extension("test"),
+        io::Error::new(ErrorKind::Other, "test").into(),
+        serde_json::from_str::<serde_json::Value>("bad").unwrap_err().into(),
+        Error::api("test"),
+    ];
+
+    for err in &errors {
+        let h = err.hints();
+        let has_context = h
+            .context
+            .iter()
+            .any(|(k, _)| k == "details" || k == "path" || k == "error_kind");
+        assert!(
+            has_context,
+            "hints().context for '{err}' should include 'details', 'path', or 'error_kind'; got: {:?}",
+            h.context,
+        );
+    }
+}
